module RefModule(input [7:0] num1, num2, input control, output reg [7:0] result, output reg carry);reg [8:0] final_sig;

    always @(*) begin
        if (control == 1'b0) begin  // addition operation
            final_sig = num1 + num2;
            carry = final_sig[8];
            result = final_sig[7:0];
        end
        else begin  // subtraction operation
            final_sig = {1'b0, num1} - {1'b0, num2}; // ensure 1-bit width for carry
            carry = final_sig[8];
            result = final_sig[7:0];
        end
    end
endmodule
